mapper.select:
SELECT *
FROM lkt_comments
WHERE store_id = #{store_id}
AND pid = #{pid}

    AND oid LIKE CONCAT(#{like_oid},'%')

ORDER BY add_time DESC

    limit #{pageNo},#{pageSize}

SELECT a.id, DATE_FORMAT(a.add_time,'%Y-%m-%d %H:%i:%s') add_time, a.content, a.CommentType, a.anonymous, a.review, DATE_FORMAT(a.review_time,'%Y-%m-%d %H:%i:%s') review_time, a.pid, a.attribute_id, m.user_name, m.headimgurl,m.user_id,goods.mch_id, case when CommentType >= 4 then '5' when CommentType = 3 then '3' when CommentType >= 1 and CommentType <= 2 then '2' end plType,d.arrive_time,goods.mch_id,a.order_detail_id FROM lkt_comments a LEFT JOIN lkt_user m ON a.uid = m.user_id AND a.store_id = m.store_id LEFT JOIN lkt_order_details d ON d.id = a.order_detail_id LEFT JOIN lkt_product_list goods ON goods.id=a.pid WHERE a.store_id = #{store_id}
a.id, add_time, a.content, a.CommentType, a.anonymous, a.review, review_time, a.pid, a.attribute_id, m.user_name, m.headimgurl, m.user_id, goods.mch_id,
ORDER BY add_time DESC
limit #{pageNo},#{pageSize}

mapper.sql:
and c.store_id = #{store_id}
AND o.sNo LIKE CONCAT('%',#{orderno},'%')
AND lm.name LIKE CONCAT('%',#{mchName},'%')
AND lm.id = #{mchId}
AND (o.sNo LIKE CONCAT('%',#{keyword},'%') or lpl.product_title LIKE CONCAT('%',#{keyword},'%'))
and o.otype=#{orderType}
and a.r_status in (5,12)
and a.r_status in (66,99)
and c.CommentType > 3
and c.CommentType =3
and c.CommentType   <   3
and exists (select x.id from lkt_comments_img x where x.comments_id=c.id limit 1)
and c.add_time   >=   #{startDate}
and c.add_time   <=   #{endDate}
and c.id=#{commentId}
and a.id=#{detailId}
and (u.user_id = #{userIdOrName} or u.user_name LIKE CONCAT('%',#{userIdOrName},'%'))
and lpl.id=#{productId}
and c.is_look = #{isLook}

    
        #{type}
    

and c.id = #{cid}

mapper.select:
SELECT a.odid, a.r_sNo, a.p_price, a.p_name, a.attrSize, a.r_status, a.z_price, a.store_id, a.oid, a.uid, a.pid, a.attribute_id, a.size, a.content, a.CommentType, a.anonymous, a.add_time, a.review, a.review_time, a.type, a.otype, a.order_detail_id, a.mch_id, a.sNo, a.id, a.shop_name, a.replyText, a.user_name, a.id, a.headimgurl, a.user_id, a.is_look, a.productId, a.product_title FROM( SELECT a.id AS odid, a.r_sNo, a.p_price, a.p_name, a.size attrSize, a.r_status, o.z_price, c.store_id, c.oid, c.uid, c.pid, c.attribute_id, c.size, c.content, c.CommentType, c.anonymous, c.add_time, c.review, c.review_time, c.type, o.otype, c.order_detail_id, o.mch_id, o.sNo, ROW_NUMBER() over(partition by c.id) AS top, lm.`name` AS shop_name, lm.id as lmid, reply.content replyText, u.user_name, c.id, u.headimgurl, u.user_id, c.is_look, lpl.id AS productId, lpl.product_title FROM lkt_order_details AS a LEFT JOIN lkt_comments AS c ON a.r_sNo = c.oid AND a.sid = c.attribute_id LEFT JOIN lkt_order AS o ON a.r_sNo = o.sNo LEFT JOIN lkt_configure AS attr ON attr.id = a.sid LEFT JOIN lkt_product_list AS lpl ON lpl.id = attr.pid LEFT JOIN lkt_mch AS lm ON lm.id = lpl.mch_id LEFT JOIN lkt_user AS u ON u.user_id = o.user_id LEFT JOIN lkt_reply_comments reply ON reply.cid = c.id AND lm.user_id = reply.uid
c.add_time ${add_time_sort} c.add_time desc
) as a where a.top =1
limit #{pageStart},#{pageEnd}
